head.script:
// 전역변수
scwin.memJson = $c.data.getMemInfo();

scwin.sDate = $c.date.getServerDateTime("");  // 서버를 기준으로 현재 날짜 반환
scwin.strFromDate = scwin.sDate.substring(0,8);
scwin.strLastDate = ($c.date.getLastDateOfMonth(scwin.strFromDate.substring(0,6)));

scwin.strToDate = scwin.strFromDate.substring(0,6) + scwin.strLastDate;
scwin.strFromDate = scwin.strFromDate.substring(0,6)+"01";

scwin.gv_loabranCd = scwin.memJson.loUpperLobranCd;
scwin.preWrkClsCd = '';

scwin.onpageload = function() {
    scwin.pDeptCd = $c.data.getParameter("pDeptCd") == null ? "" : $c.data.getParameter("pDeptCd");
    scwin.pVehchlNo = $c.data.getParameter("pVehchlNo") == null ? "" : $c.data.getParameter("pVehchlNo");
    scwin.pDrcrNo = $c.data.getParameter("pDrcrNo") == null ? "" : $c.data.getParameter("pDrcrNo");
    scwin.pApplyDt = $c.data.getParameter("pApplyDt") == null ? "" : $c.data.getParameter("pApplyDt");
    scwin.pPorteYn = $c.data.getParameter("pPorteYn") == null ? "" : $c.data.getParameter("pPorteYn");

	const codeOptions = [
        {
            method: "getLuxeComboDataNoSort",
            param1: "VehclInsuranceMgntEBC",
            param2: "retriveLobranCodeList",
            compID: "acb_reqDeptCd"
        },        
        {
            method: "getLuxeComboDataNoSort",
            param1: "VehclInsuranceMgntEBC",
            param2: "retriveLobranCodeList",
            compID: "acb_deptCd"
        },

    ];
    $c.data.setGauceUtil(codeOptions, function(){
        if (scwin.gv_loabranCd != null) {
            acb_reqDeptCd.setValue(scwin.gv_loabranCd);
        } else {
            acb_reqDeptCd.setValue('');
        }

        if (scwin.pPorteYn == "Y") {
            acb_reqDeptCd.setValue(scwin.pDeptCd);
            $c.gus.cfDisableObjects([acb_reqDeptCd]);
        }
    });

    const codeOptions2 = [
        { grpCd: "ZZ831", compID: "rd_wrkClsCd" },//rd_wrkClsCd
        { grpCd: "ZZ832", compID: "acb_reqPossessCd,lc_possessCd" },
        { grpCd: "ZZ833", compID: "lc_vehclTypeCd",opt : {"range" : "1"} },
        { grpCd: "ZZ843", compID: "lc_cancelCd" },
        { grpCd: "ZZ840", compID: "lc_driverAge" },
        { grpCd: "ZZ835", compID: "lc_objectLimitCd" },
        { grpCd: "ZZ836", compID: "lc_guaranteeLimitCd" },
        { grpCd: "ZZ838", compID: "",opt : {"range" : "1"} },
        { grpCd: "ZZ844", compID: "rd_indDistrWrkClsCd" },//rd_indDistrWrkClsCd
        { grpCd: "ZZ845", compID: "lc_indDistrSndTypeCd" }
    ];
    $c.data.setCommonCode(codeOptions2, function() {
        dlt_commonCodeZZ838.insertRow(0);
        dlt_commonCodeZZ838.setCellData(0,"cd","00");
        dlt_commonCodeZZ838.setCellData(0,"cdNm","선택하지않음");

        for(let i = 0; i < dlt_commonCodeZZ838.getRowCount(); i++) {
            let newRow = ds_fileType.insertRow();
            ds_fileType.setCellData(newRow, "code", dlt_commonCodeZZ838.getCellData(i,"cd"));
            ds_fileType.setCellData(newRow, "name", dlt_commonCodeZZ838.getCellData(i,"cdNm"));
        }
    });
};

//-------------------------------------------------------------------------
// UDC 로딩 완료 후
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    scwin.f_firstSetting();

    ed_reqApplyStdDt.setValue(scwin.strFromDate);
    ed_reqApplyEndDt.setValue(scwin.strToDate);
};

scwin.ondataload = async function() {  
    if (scwin.pPorteYn == "Y") {
        ed_reqVehclNo.setValue(scwin.pVehchlNo);
        ed_reqDrcrNo.setValue(scwin.pDrcrNo);
        ed_reqApplyStdDt.setValue(scwin.pApplyDt);
        ed_reqApplyEndDt.setValue(scwin.pApplyDt);

        $c.gus.cfDisableObjects([ed_reqVehclNo, ed_reqDrcrNo, acb_reqPossessCd, udc_reqApply, btn_retrive]); 
        $c.gus.cfDisableObjects([btn_create, btn_update, btn_cancel, btn_save]);
        scwin.f_Retrieve();
    }

    //(dlt_commonCodeZZ838);
    dma_attachCond.set("mgntNo", "1");
    dma_attachCond.set("wrkSeq", "1");

    udcFileUpload.setTypeData(ds_fileType.getAllJSON(), true);
    let e = await $c.sbm.execute(sbm_retrieveAttachFile);
    scwin.sbm_retrieveAttachFile_submitdone(e);
}

//-------------------------------------------------------------------------
// Enable/Disable
//-------------------------------------------------------------------------
scwin.f_firstSetting = function() {
    $c.gus.cfDisableKeyData();      

    // 기본정보 항목
    $c.gus.cfDisableObjects([rd_wrkClsCd, acb_deptCd, ed_applyDt, ed_vehclNo, ed_drcrNo, lc_cancelCd, lc_possessCd, lc_vehclTypeCd, ed_maxPayloadCd, ed_releaseYear]); 

    // 자동차보험 항목
    //cfDisableObjects([ed_carInsuranceShortStdDt, ed_carInsuranceShortEndDt, img_carInsuranceShortStdDt, img_carInsuranceShortEndDt]); 
    $c.gus.cfDisableObjects([udc_carInsuranceYear]); 
    $c.gus.cfDisableObjects([lc_objectLimitCd, lc_driverAge]); 
    $c.gus.cfDisableObjects([cbx_selfVehclYn, udc_selfVehcl]); 
    $c.gus.cfDisableObjects([cbx_sfdmgVehclYn, udc_sfdmgVehcl]); 

    // 적재물보험 항목
    //cfDisableObjects([ed_luggageInsuranceShortStdDt, ed_luggageInsuranceShortEndDt, img_luggageInsuranceShortStdDt, img_luggageInsuranceShortEndDt]); 
    $c.gus.cfDisableObjects([udc_luggageInsuranceYear]); 
    $c.gus.cfDisableObjects([lc_guaranteeLimitCd]); 
    $c.gus.cfDisableObjects([cbx_glassYn, udc_glass]); 
    $c.gus.cfDisableObjects([cbx_frizYn, udc_friz]); 
    //cfDisableObjects([chb_umbrellaPolicyYn, ed_umbrellaPolicyStdDt, ed_umbrellaPolicyEndDt, img_umbrellaPolicyStdDt, img_umbrellaPolicyEndDt]);

    // 버튼 항목
    $c.gus.cfDisableObjects([btn_create, btn_update, btn_cancel, btn_save]);

    // 산재보험 항목
    $c.gus.cfDisableObjects([udc_indDistr, ed_indDistrDrvNm, ed_indDistrBirthDt, rd_indDistrWrkClsCd, lc_indDistrSndTypeCd]); 
};

//-------------------------------------------------------------------------
// Enable
//-------------------------------------------------------------------------
scwin.f_enableSetting = function() {
    // 기본정보
    $c.gus.cfEnableObjects([acb_deptCd, ed_vehclNo, ed_drcrNo, lc_possessCd, lc_vehclTypeCd, ed_maxPayloadCd, ed_releaseYear]);

    // 자동차 보험
    //cfEnableObjects([ed_carInsuranceShortStdDt, ed_carInsuranceShortEndDt, img_carInsuranceShortStdDt, img_carInsuranceShortEndDt]); 
    $c.gus.cfEnableObjects([udc_carInsuranceYear]); 
    $c.gus.cfEnableObjects([lc_objectLimitCd, lc_driverAge, cbx_selfVehclYn, cbx_sfdmgVehclYn]);

    // 적재물 보험
    //cfEnableObjects([ed_luggageInsuranceShortStdDt, ed_luggageInsuranceShortEndDt, img_luggageInsuranceShortStdDt, img_luggageInsuranceShortEndDt]); 
    $c.gus.cfEnableObjects([udc_luggageInsuranceYear]); 
    $c.gus.cfEnableObjects([lc_guaranteeLimitCd, cbx_glassYn, cbx_frizYn]);//, chb_umbrellaPolicyYn]); 

    scwin.f_checkSelfVehclYn();
    scwin.f_checkSfdmgVehclYn();
    scwin.f_checkGlassYn();
    scwin.f_checkFrizYn();
    //scwin.f_checkUmbrellaPolicyYn();

    // 산재보험 항목
    $c.gus.cfEnableObjects([udc_indDistr, ed_indDistrDrvNm, ed_indDistrBirthDt, rd_indDistrWrkClsCd, lc_indDistrSndTypeCd]);       
};    

//-------------------------------------------------------------------------
// onloadSetting
//-------------------------------------------------------------------------
scwin.f_onloadSetting = function() {
    scwin.f_firstSetting();

    let row = ds_vehclInsuranceMgnt.getRowPosition();
    if (row < 0) return;

    let chkWrkClsCd      = ds_vehclInsuranceMgnt.getCellData(row,"wrkClsCd");
    let chkApprvReqNo    = ds_vehclInsuranceMgnt.getCellData(row,"apprvReqNo");
    let chkApprvStsCd    = ds_vehclInsuranceMgnt.getCellData(row,"apprvStsCd");

    if(chkApprvReqNo == ''){    // 전자결재 올리지 않은 상태 (수정이 가능 해야함)
        $c.gus.cfEnableObjects([btn_create, btn_update]);
    }
    else{
        if(chkApprvStsCd == '05' || chkApprvStsCd == '03' || chkApprvStsCd == '06' ){   // 전자결재 최종완결 상태와 반려 상태 (수정이 가능 해야함)
            $c.gus.cfEnableObjects([btn_create, btn_update]);

        }   
        else{   // 전자결재는 상신했음 ~ 나머지 상태들 (신규만 가능)
            $c.gus.cfEnableObjects([btn_create]);
        }
    }

    if(chkWrkClsCd == '02' && chkApprvStsCd == '01'){
        if(scwin.pPorteYn == ''){
            $c.gus.cfEnableObjects([btn_create, btn_update]);
        }
    }
};  

//-------------------------------------------------------------------------
// 신규 버튼 클릭시
//------------------------------------------------------------------------- 
scwin.f_Create = function() {
    let newRow = ds_vehclInsuranceMgnt.insertRow();
    gr_vehclInsuranceMgnt.setFocusedCell(newRow, "wrkClsCd");

    ds_vehclInsuranceMgnt.setCellData(newRow, "wrkClsCd", '01');   // 작업구분
    ds_vehclInsuranceMgnt.setCellData(newRow, "deptCd", scwin.gv_loabranCd);  // 소속지사
    ds_vehclInsuranceMgnt.setCellData(newRow, "applyDt", $c.date.getServerDateTime("yyyyMMdd")); // 신청일자

    scwin.f_enableSetting(); 
    $c.gus.cfEnableObjects([rd_wrkClsCd, btn_cancel, btn_save]);
    $c.gus.cfDisableObjects([btn_create, btn_update]);
};      

//-------------------------------------------------------------------------
// 수정 버튼 클릭시
//-------------------------------------------------------------------------             
scwin.f_Update = function() {
    $c.gus.cfDisableObjects([btn_create, btn_update]);
    $c.gus.cfEnableObjects([rd_wrkClsCd, btn_cancel, btn_save]);
    rd_wrkClsCd.focus();

    let row = ds_vehclInsuranceMgnt.getRowPosition();

    ds_vehclInsuranceMgnt.setCellData(row, "applyDt", $c.date.getServerDateTime("yyyyMMdd")); // 신청일자

    let chkWrkClsCd = ds_vehclInsuranceMgnt.getCellData(row,"wrkClsCd");

    if(chkWrkClsCd == '01'){        // 가입 상태인 경우 모든 메뉴 수정 가능
        scwin.f_enableSetting();
    }
    else if(chkWrkClsCd == '02'){   // 변경 상태인 경우 [기본정보: 소속지사, 차량번호, 차대번호, 최대적재량, 차량년식, 소유구분, 차량형식]
        // [자동차보험정보: 자차, 자손, 운전자연령, 대물한도],[적재물보험정보: 유리특약, 냉동특약, 보상한도] 수정가능
        scwin.f_enableSetting();
        //$c.gus.cfDisableObjects([ed_maxPayloadCd, ed_releaseYear]);
    }
    else if(chkWrkClsCd == '03'){   // 대차를 선택 하는 경우 차대번호, 최대적재량, 차량년식, 소속지사, 소유구분만 수정 가능
        $c.gus.cfEnableObjects([ed_drcrNo, ed_maxPayloadCd, ed_releaseYear, acb_deptCd, lc_possessCd]);
    }
    else if(chkWrkClsCd == '04'){   // 갱신 상태인 경우 모든 메뉴 수정 가능
        scwin.f_enableSetting();
    }
    else if(chkWrkClsCd == '05'){   // 해지를 선택 하는 경우 보험기간, 해지사유만 수정 가능           
        //$c.gus.cfEnableObjects([ed_carInsuranceShortStdDt, ed_carInsuranceShortEndDt, img_carInsuranceShortStdDt, img_carInsuranceShortEndDt]);
        $c.gus.cfEnableObjects([lc_cancelCd, udc_carInsuranceYear]);
        //$c.gus.cfEnableObjects([ed_luggageInsuranceShortStdDt, ed_luggageInsuranceShortEndDt, img_luggageInsuranceShortStdDt, img_luggageInsuranceShortEndDt]);
        $c.gus.cfEnableObjects([udc_luggageInsuranceYear]);
    }

    if(ds_vehclInsuranceMgnt.getCellData(row,"apprvStsCd") != '05'){
        $c.gus.cfDisableObjects([rd_wrkClsCd]);
    }
};

//-------------------------------------------------------------------------
// 취소 버튼 클릭시
//-------------------------------------------------------------------------
scwin.f_Cancel = function() {
    $c.data.undoRow(ds_vehclInsuranceMgnt);
    rd_wrkClsCd.focus();

    scwin.f_firstSetting();
    scwin.f_onloadSetting();
};   

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() { 
    if(ed_reqApplyStdDt.getValue() == "" || ed_reqApplyEndDt.getValue() == ""){
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_002, "신청일자"));
        ed_reqApplyStdDt.focus();
        return;
    }

    //시작일자가 종료일자 이전인지 check
    if (!$c.gus.cfIsAfterDate(ed_reqApplyStdDt.getValue(), ed_reqApplyEndDt.getValue())){
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_039));
        return;
    }

    $c.sbm.execute(sbm_search);

    //scwin.f_setFileUpDownFrame(slipNo);
};

//-------------------------------------------------------------------------
// 공통코드 조회 - 전 (past)
//-------------------------------------------------------------------------     
scwin.f_cdNm = async function(GRP_CD, CD) {
    let grp_cd = GRP_CD;
    let pCode = CD;

    // SELECT 절 
    let param1 =  
      " CD_NM      as COL1 "
    + ",''      as COL2 "
    + ",''      as COL3 "
    + ",''      as COL4 "
    + ",''      as COL5 "
    + ",''      as COL6 "
    + ",''      as COL7 "
    + ",''      as COL8 "
    + ",''      as COL9 "
    + ",''      as COL10";

    // 대상테이블     
    let param2 = " TB_ZZ002 ";

    // 조건절
    let param3 =  
          " AND GRP_CD = '"+grp_cd+"'" 
        + " AND CD = '"+pCode+"'" 
        ;

    let param4 =  "CD_NM";

    dma_cdNm.set("param1", param1);
    dma_cdNm.set("param2", param2);
    dma_cdNm.set("param3", param3);
    dma_cdNm.set("param4", param4);

    sbm_cdNm.action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=dinymicQueryTest" + "&param1=" + param1 + "&param2=" + param2 + "&param3=" + param3 + "&param4=" + param4;
    await $c.sbm.execute(sbm_cdNm);  
};  

scwin.check_Num = function(a) {
    let num = a;
    let j;
    let t = false;

    //소수점 유무 판별
    for( j = 1; j <= num.length; j++){
        if(num.substring(j-1,j)=='.'){
            t = true; //소수점 있음
        }
    }

    //소수점 몇 자리인지 판별
    if(t == true){
        num = (num=num.toString()).substring(num.indexOf('.')+1, num.length)
        if(num.length > 1) { //소수점 2자리 이상
            return false;
        }else{  //소수점 1자리 이하
            return true;
        }
    }else{  //소수점 없음
        return true;
    }
};

//-------------------------------------------------------------------------
// 저장 버튼 클릭시
//-------------------------------------------------------------------------
scwin.f_Save = async function() {
    if (ds_vehclInsuranceMgnt.getModifiedIndex().length == 0) {
        await $c.win.alert("변경된 사항이 없습니다.");
        return;
    }

    let oValidExp = {dataName:"차량보험신청관리",
    validFeatures:"ignoreStatus=no,",
    validExp:`wrkClsCd:작업구분:yes, deptCd:소속지사:yes, applyDt:신청일:yes, drcrNo:차대번호:yes, possessCd:소유구분:yes, 
                    vehclTypeCd:차량형식:yes, maxPayloadCd:최대적재랑:yes, releaseYear:차량년식:yes, 
                    carInsuranceYearStdDt:자동차보험기간1년:yes, carInsuranceYearEndDt:자동차보험기간1년:yes,
                    luggageInsuranceYearStdDt:적재물보험기간1년:yes, luggageInsuranceYearEndDt:적재물보험기간1년:yes,
                    driverAge:운전자연령:yes, objectLimitCd:대물한도:yes, guaranteeLimitCd:보상한도:yes,
                    indDistrStdDt:입직일:yes, indDistrEndDt:이직/적용제외신청일:yes, indDistrDrvNm:운전자명:yes,
                    indDistrBirthDt:생년월일:yes, indDistrWrkClsCd:산재작업구분:yes`};
    await $c.gus.setValidExp(gr_vehclInsuranceMgnt, oValidExp);            

    let ret = await $c.gus.cfValidate([gr_vehclInsuranceMgnt], null, true);
    if (ret) {
        let row = ds_vehclInsuranceMgnt.getRowPosition();
        if (ds_vehclInsuranceMgnt.getCellData(row,"wrkClsCd") == '02' || ds_vehclInsuranceMgnt.getCellData(row,"wrkClsCd") == '03') { // 변경 또는 대차 상태인 경우

            let pastCdNm = '';
            let currentCdNm = '';

            //'변경 및 대차 내역' 자동저장을 위한 데이터 설정
            if(ds_vehclInsuranceMgnt.getCellData(row,"deptCd") != ds_vehclInsuranceMgnt.getCellData(row,"preDeptCd")){
                let newRow = ds_vehclInsuranceMgntChangeDetail.insertRow();
                ds_vehclInsuranceMgntChangeDetail.setCellData(newRow, 'mgntNo', ds_vehclInsuranceMgnt.getCellData(row,"mgntNo"));             
                ds_vehclInsuranceMgntChangeDetail.setCellData(newRow, "chgWrkCd", '01'); //소속지사                    

                await scwin.f_cdNm('ZZ842', ds_vehclInsuranceMgnt.getCellData(row,"preDeptCd")); //변경전 
                pastCdNm = ds_cdNm.getCellData(0, "col1");

                await scwin.f_cdNm('ZZ842', ds_vehclInsuranceMgnt.getCellData(row,"deptCd")); //변경후 
                currentCdNm = ds_cdNm.getCellData(0, "col1");

                ds_vehclInsuranceMgntChangeDetail.setCellData(newRow, "pastData", pastCdNm);
                ds_vehclInsuranceMgntChangeDetail.setCellData(newRow, "currentData", currentCdNm);
            }

            if(ds_vehclInsuranceMgnt.getCellData(row,"vehclNo") != ds_vehclInsuranceMgnt.getCellData(row,"preVehclNo")){
                let newRow = ds_vehclInsuranceMgntChangeDetail.insertRow();
                ds_vehclInsuranceMgntChangeDetail.setCellData(newRow, 'mgntNo', ds_vehclInsuranceMgnt.getCellData(row,"mgntNo"));            
                ds_vehclInsuranceMgntChangeDetail.setCellData(newRow, "chgWrkCd", '02'); //차량번호
                ds_vehclInsuranceMgntChangeDetail.setCellData(newRow, "pastData", ds_vehclInsuranceMgnt.getCellData(row,"preVehclNo"));
                ds_vehclInsuranceMgntChangeDetail.setCellData(newRow, "currentData", ds_vehclInsuranceMgnt.getCellData(row,"vehclNo"));
            }

            if(ds_vehclInsuranceMgnt.getCellData(row,"drcrNo") != ds_vehclInsuranceMgnt.getCellData(row,"preDrcrNo")){
                let newRow = ds_vehclInsuranceMgntChangeDetail.insertRow();
                ds_vehclInsuranceMgntChangeDetail.setCellData(newRow, 'mgntNo', ds_vehclInsuranceMgnt.getCellData(row,"mgntNo"));            
                ds_vehclInsuranceMgntChangeDetail.setCellData(newRow, "chgWrkCd", '03'); //차대번호
                ds_vehclInsuranceMgntChangeDetail.setCellData(newRow, "pastData", ds_vehclInsuranceMgnt.getCellData(row,"preDrcrNo"));
                ds_vehclInsuranceMgntChangeDetail.setCellData(newRow, "currentData", ds_vehclInsuranceMgnt.getCellData(row,"drcrNo"));
            }

            if(ds_vehclInsuranceMgnt.getCellData(row,"maxPayloadCd") != ds_vehclInsuranceMgnt.getCellData(row,"preMaxPayloadCd")){
                let newRow = ds_vehclInsuranceMgntChangeDetail.insertRow();
                ds_vehclInsuranceMgntChangeDetail.setCellData(newRow, 'mgntNo', ds_vehclInsuranceMgnt.getCellData(row,"mgntNo"));            
                ds_vehclInsuranceMgntChangeDetail.setCellData(newRow, "chgWrkCd", '04'); //최대적재량(톤) 공통코드 안 씀                                                        
                ds_vehclInsuranceMgntChangeDetail.setCellData(newRow, "pastData", ds_vehclInsuranceMgnt.getCellData(row,"preMaxPayloadCd"));
                ds_vehclInsuranceMgntChangeDetail.setCellData(newRow, "currentData", ds_vehclInsuranceMgnt.getCellData(row,"maxPayloadCd"));

            }

            if(ds_vehclInsuranceMgnt.getCellData(row,"releaseYear") != ds_vehclInsuranceMgnt.getCellData(row,"preReleaseYear")){
                let newRow = ds_vehclInsuranceMgntChangeDetail.insertRow();
                ds_vehclInsuranceMgntChangeDetail.setCellData(newRow, 'mgntNo', ds_vehclInsuranceMgnt.getCellData(row,"mgntNo"));            
                ds_vehclInsuranceMgntChangeDetail.setCellData(newRow, "chgWrkCd", '05'); //차량년식
                ds_vehclInsuranceMgntChangeDetail.setCellData(newRow, "pastData", ds_vehclInsuranceMgnt.getCellData(row,"preReleaseYear"));
                ds_vehclInsuranceMgntChangeDetail.setCellData(newRow, "currentData", ds_vehclInsuranceMgnt.getCellData(row,"releaseYear"));
            }

