            await $c.win.alert("자동차보험 정보 기간(1년)의 시작일자가 종료일자 전 이어야 합니다");
            ed_carInsuranceYearStdDt.focus();
            return;
        }

        //시작일자가 종료일자 이전인지 check
        if (!$c.gus.cfIsAfterDate(chkLuggageInsuranceYearStdDt, chkLuggageInsuranceYearEndDt)){
            await $c.win.alert("적재물보험 정보 기간(1년)의 시작일자가 종료일자 전 이어야 합니다");
            ed_luggageInsuranceYearStdDt.focus();
            return;
        }

        //시작일자가 종료일자 이전인지 check
        if (!$c.gus.cfIsAfterDate(chkIndDistrStdDt, chkIndDistrEndDt)){
            await $c.win.alert("산재보험 보험 기간의 시작일자가 종료일자 전 이어야 합니다");
            ed_indDistrStdDt.focus();
            return;
        }

        if(chkSelfVehclYn == '1'){      // 자차여부
            let chkSelfVehclStdDt = ds_vehclInsuranceMgnt.getCellData(row,"selfVehclStdDt");
            let chkSelfVehclEndDt = ds_vehclInsuranceMgnt.getCellData(row,"selfVehclEndDt");

            if(chkSelfVehclStdDt == '' || chkSelfVehclEndDt == ''){
                await $c.win.alert("자차여부 선택시 시작일자와 종료일자를 입력 해야합니다.");
                ed_selfVehclStdDt.focus();
                return;
            }

            if (!$c.gus.cfIsAfterDate(chkSelfVehclStdDt, chkSelfVehclEndDt)){
                await $c.win.alert("자차여부 선택시 자차기간 시작일자가 종료일자 전 이어야 합니다");
                ed_selfVehclStdDt.focus();
                return;
            }
        }

        if(chkSfdmgVehclYn == '1'){     // 자손여부
            let chkSfdmgVehclStdDt = ds_vehclInsuranceMgnt.getCellData(row,"sfdmgVehclStdDt");
            let chkSfdmgVehclEndDt = ds_vehclInsuranceMgnt.getCellData(row,"sfdmgVehclEndDt");

            if(chkSfdmgVehclStdDt == '' || chkSfdmgVehclEndDt == ''){
                await $c.win.alert("자손여부 선택시 시작일자와 종료일자를 입력 해야합니다.");
                ed_sfdmgVehclStdDt.focus();
                return;
            }

            if (!$c.gus.cfIsAfterDate(chkSfdmgVehclStdDt, chkSfdmgVehclEndDt)){
                await $c.win.alert("자손여부 선택시 자손여부 시작일자가 종료일자 전 이어야 합니다");
                ed_sfdmgVehclStdDt.focus();
                return;
            }
        }

        if(chkGlassYn == '1'){          // 유리여부
            let chkGlassStdDt = ds_vehclInsuranceMgnt.getCellData(row,"glassStdDt");
            let chkGlassEndDt = ds_vehclInsuranceMgnt.getCellData(row,"glassEndDt");

            if(chkGlassStdDt == '' || chkGlassEndDt == ''){
                await $c.win.alert("유리여부 선택시 시작일자와 종료일자를 입력 해야합니다.");
                ed_glassStdDt.focus();
                return;
            }

            if (!$c.gus.cfIsAfterDate(chkGlassStdDt, chkGlassEndDt)){
                await $c.win.alert("유리여부 선택시 유리여부 시작일자가 종료일자 전 이어야 합니다");
                ed_glassStdDt.focus();
                return;
            }
        }

        if(chkFrizYn == '1'){               // 냉동여부
            let chkFrizStdDt = ds_vehclInsuranceMgnt.getCellData(row,"frizStdDt");
            let chkFrizEndDt = ds_vehclInsuranceMgnt.getCellData(row,"frizEndDt");

            if(chkFrizStdDt == '' || chkFrizEndDt == ''){
                await $c.win.alert("냉동여부 선택시 시작일자와 종료일자를 입력 해야합니다.");
                ed_frizStdDt.focus();
                return;
            }

            if (!$c.gus.cfIsAfterDate(chkFrizStdDt, chkFrizEndDt)){
                await $c.win.alert("냉동여부 선택시 냉동여부 시작일자가 종료일자 전 이어야 합니다");
                ed_frizStdDt.focus();
                return;
            }
        }

        if(chkWrkClsCd == '05'){
            let chkCancelCd = ds_vehclInsuranceMgnt.getCellData(row,"cancelCd");

            if(chkCancelCd == ''){
                await $c.win.alert("작업구분 해지 상태의 경우 해지사유는 필수입력 입니다.");
                lc_cancelCd.focus();
                return;
            }
        }

        if(await $c.win.confirm(MSG_CM_CRM_001)==true){
            $c.sbm.execute(sbm_save);        
        }else{
            if(ds_vehclInsuranceMgntChangeDetail.getRowCount() > 0){
                for(let i=ds_vehclInsuranceMgntChangeDetail.getRowCount()-1; i>=0; i--){
                    if($c.gus.cfIsNull(ds_vehclInsuranceMgntChangeDetail.getCellData(i,"chkBox"))){
                        $c.data.undoRow(ds_vehclInsuranceMgntChangeDetail);
                    }
                }
            }
        }
    }
};

