scwin.sbm_search_submitdone = async function (e) {
    let rowCnt = ds_vehclInsuranceMgnt.getRowCount();

    if (rowCnt == 0) {
        await $c.win.alert("조회결과가 존재하지 않습니다.");
        $c.gus.cfEnableObjects([btn_create]);
    }
    else {
        gr_vehclInsuranceMgnt.setFocusedCell(0, "wrkClsCd");
        totalRows.setValue(rowCnt);

        scwin.f_onloadSetting();

        dma_condition2.set('mgntNo', ds_vehclInsuranceMgnt.getCellData(0,'mgntNo'));    
        dma_condition2.set('wrkSeq', ds_vehclInsuranceMgnt.getCellData(0,'wrkSeq'));    

        let e = await $c.sbm.execute(sbm_retrieve_detail);

        // 로드 되었을때 첫번째 작업구분값
        scwin.preWrkClsCd = ds_vehclInsuranceMgnt.getCellData(0,'wrkClsCd');    

        if (scwin.pPorteYn == "Y"){
            $c.gus.cfDisableObjects([btn_create]);
        }

        scwin.f_attachFileList();
    }
};

scwin.gr_vehclInsuranceMgnt_oncellclick = async function (rowIndex, columnIndex, columnId) {
    scwin.f_onloadSetting();

    dma_condition2.set('mgntNo', ds_vehclInsuranceMgnt.getCellData(rowIndex,'mgntNo'));    
    dma_condition2.set('wrkSeq', ds_vehclInsuranceMgnt.getCellData(rowIndex,'wrkSeq'));    

    await $c.sbm.execute(sbm_retrieve_detail);

    // 클릭시 현재 행의 작업구분값
    scwin.preWrkClsCd = ds_vehclInsuranceMgnt.getCellData(rowIndex,'wrkClsCd');    
    rd_wrkClsCd.focus();

    if(ds_vehclInsuranceMgnt.getRowStatus(rowIndex) == "C"){
        return false;
    }

    $c.gus.cfDisableKeyData();

    if(ds_vehclInsuranceMgnt.getRowStatus(rowIndex) != "C"){
        $c.data.undoAll(ds_vehclInsuranceMgnt);
        gr_vehclInsuranceMgnt.setFocusedCell(rowIndex, "wrkClsCd");
    }
};

