    scwin.f_attachFileList();
};

scwin.ds_vehclInsuranceMgnt_oncelldatachange = async function (info) {
    let row = info.rowIndex;
    let colid = info.colID;

    if (colid == "wrkClsCd") {
        scwin.f_firstSetting();
        $c.gus.cfEnableObjects([rd_wrkClsCd, btn_cancel, btn_save]);

        let chkWrkClsCd      = ds_vehclInsuranceMgnt.getCellData(row,"wrkClsCd");
        let chkApprvReqNo    = ds_vehclInsuranceMgnt.getCellData(row,"apprvReqNo");
        let chkApprvStsCd    = ds_vehclInsuranceMgnt.getCellData(row,"apprvStsCd");

        if(chkWrkClsCd == '01' && ed_drcrNo.getValue() != ''){
            ds_vehclInsuranceMgnt.setCellData(row, 'wrkClsCd', scwin.preWrkClsCd);

            await $c.win.alert("작업구분을 가입을 선택 하셨습니다.\n\n"
                  + "신규등록만 가입 선택이 가능 합니다.");
            scwin.f_onloadSetting();
            $c.data.undoRow(ds_vehclInsuranceMgnt);
            return;
        }
        else if(chkWrkClsCd == '02'){   
            $c.gus.cfEnableObjects([btn_update]);
            scwin.f_enableSetting();
        }
        else if(chkWrkClsCd == '03'){   
            $c.gus.cfEnableObjects([ed_drcrNo, ed_maxPayloadCd, ed_releaseYear, acb_deptCd, lc_possessCd]);
        }
        else if(chkWrkClsCd == '04'){   
            await $c.win.alert("작업구분을 갱신을 선택 하셨습니다.\n\n"
                  + "갱신 상태로의 변경은 '차량보험일괄갱신'탭 에서만 처리 가능 합니다.");
            $c.data.undoRow(ds_vehclInsuranceMgnt);
            gr_vehclInsuranceMgnt.setFocusedCell(ds_vehclInsuranceMgnt.getRowPosition(), "wrkClsCd");
            scwin.f_onloadSetting();
            return;
        }
        else if(chkWrkClsCd == '05'){   
            $c.gus.cfEnableObjects([lc_cancelCd, udc_carInsuranceYear]);
            $c.gus.cfEnableObjects([udc_luggageInsuranceYear]);

            ds_vehclInsuranceMgnt.setCellData(row, "carInsuranceYearEndDt", $c.date.getServerDateTime("yyyyMMdd"));
            ds_vehclInsuranceMgnt.setCellData(row, "luggageInsuranceYearEndDt", $c.date.getServerDateTime("yyyyMMdd"));
        }
    }
};

scwin.sbm_retrieveAttachFile_submitdone = function (e) {
    udcFileUpload.setType("00");
    let fileJson = [];
    for (let i = 0 ; i < ds_fileList.getRowCount() ; i ++){
        let attachFilePath = ds_fileList.getCellData(i, "filePath")

        let fileStoredPath = attachFilePath.substr(0, attachFilePath.lastIndexOf('/')+1);
        let storedFileNm = attachFilePath.substr(attachFilePath.lastIndexOf('/')+1);

        let fileInfoData = {
            FILE_EXPLAIN        : ""
            , FILE_SIZE         : ds_fileList.getCellData(i, "fileSize")
            , FILE_STORED_PATH  : fileStoredPath
            , ORIGIN_FILE_NM    : ds_fileList.getCellData(i, "fileName")
            , STORED_FILE_NM    : storedFileNm
            , chk               : "0"
            , evidClsNm         : ds_fileList.getCellData(i, "fileClsCd")
            , hiddenKey         : ""
            , preView           : ""
            , receptYn          : ""
            , rowStatus         : ds_fileList.getCellData(i, "rowStatus")
            , slipKndNm         : ""
            , slipNo            : ""
            , status            : ""
        }
        fileJson.push(fileInfoData);
    }
    udcFileUpload.setData(fileJson);
};

scwin.udcFileUpload_onFileUploadDone = function (isSuccess) {
    if (!isSuccess) return;

    let attachData = udcFileUpload.getData();
    fileUploadGDS.removeAll();

    for(let i = 0; i < attachData.length; i++) {
        if (attachData[i].status == "Completed"){
            let rowIndex = fileUploadGDS.insertRow();
            fileUploadGDS.setCellData(rowIndex, "fileName"   , attachData[i].ORIGIN_FILE_NM); //파일명
            fileUploadGDS.setCellData(rowIndex, "fileSize"  , attachData[i].FILE_SIZE); //파일SIZE
            fileUploadGDS.setCellData(rowIndex, "filePath" , attachData[i].FILE_STORED_PATH + attachData[i].STORED_FILE_NM);	//파일경로
        }
    }

    let mgntNo = ds_vehclInsuranceMgnt.getCellData(ds_vehclInsuranceMgnt.getRowPosition(), "mgntNo") || "1";
    let wrkSeq = ds_vehclInsuranceMgnt.getCellData(ds_vehclInsuranceMgnt.getRowPosition(), "wrkSeq") || "1";
    dma_mgntNo.set("mgntNo", mgntNo);// 상차요청번호
    dma_wrkSeq.set("wrkSeq", wrkSeq);// 자가운송사코드
    dma_fileClsCd.set("fileClsCd", udcFileUpload.getType());

    $c.sbm.execute(sbm_create);
};

scwin.f_fileSave = async function() {
    let fileList = udcFileUpload.getData();
    let iCnt = 0;
    let dCnt = 0;
    for (let idx in fileList) {
        let rowStatus = fileList[idx].rowStatus;
        switch (rowStatus) {
            case "C":
                iCnt++;
                break;
            case "D":
                dCnt++;
                break;
            default:
                break;
        }
    }
    //등록, 삭제가 둘다 있는 경우
    if (iCnt > 0 && dCnt > 0) {
        await $c.win.alert("신규등록과 삭제를 같이 할 수 없습니다.");
        return;
    } else {
        if (iCnt > 0) {
            scwin.fileSubmit();
        } else if (dCnt > 0) {
            scwin.fileDelete();
        } else {
            if(udcFileUpload.getType() == "00"){
                await $c.win.alert("증빙파일종류를 선택해 주시기 바랍니다.");
                return;
            }

            await $c.gus.cfAlertMsg(MSG_CM_ERR_049, ["등록할 파일"]);
            return;
        }
    }
}

scwin.fileSubmit = async function () {
    //증빙파일종류 선택하지 않으면 업로드 불가
    if(udcFileUpload.getType() == "00"){
        await $c.win.alert("증빙파일종류를 선택해 주시기 바랍니다.");
        return;
    }
    if (!await $c.win.confirm("파일을 업로드 하시겠습니까?")) {
        return;
    }

    udcFileUpload.startFileUpload();
};

scwin.fileDelete = async function () {
    if (!await udcFileUpload.isModified()) {
        await $c.win.alert("삭제 할 파일이 없습니다.");
        return;
    }

    //UDC에서 값 넘겨 받기
    fileDeleteGDS.removeAll();

    let fileList = udcFileUpload.getData();
    for (let idx in fileList) {
        let chk = fileList[idx].chk;
        if (chk == "1") {
            let row = fileDeleteGDS.insertRow();
            let hiddenKey = fileList[idx].hiddenKey;
            let delVal = hiddenKey.split("||");

            fileDeleteGDS.setCellData(row, "mgntNo", ds_fileList.getCellData(idx, "mgntNo"));
            fileDeleteGDS.setCellData(row, "fileSeq", ds_fileList.getCellData(idx, "fileSeq"));
        }
    }

    if (await $c.win.confirm("선택하신 파일을 정말로 삭제하시겠습니까")) {
        $c.sbm.execute(sbm_delete);
    }
}
scwin.sbm_delete_submitdone = async function (e) {
    await $c.win.alert("삭제가 완료 되었습니다.");
    scwin.f_Retrieve();
};

scwin.sbm_create_submitdone = async function (e) {
    await $c.win.alert("업로드가 완료 되었습니다.");
    scwin.f_Retrieve();
};

